function getNext19(){const t=new Date,n=3,o=t.getTime()+t.getTimezoneOffset()*6e4,s=new Date(o+n*36e5),e=new Date(s);e.setHours(19,0,0,0),s>=e&&e.setDate(e.getDate()+1);const i=e.getTime()-n*36e5,a=new Date(i-t.getTimezoneOffset()*6e4);return a}function updateCountdown(){const t=new Date,n=getNext19(),e=n-t,s=Math.floor(e/(1e3*60*60)),o=Math.floor(e%(1e3*60*60)/(1e3*60)),i=Math.floor(e%(1e3*60)/1e3);document.getElementById("countdown").textContent=`${String(s).padStart(2,"0")}:${String(o).padStart(2,"0")}:${String(i).padStart(2,"0")}`}updateCountdown(),setInterval(updateCountdown,1e3)